func:
// Query Calipso mejorado — busca por código de cuenta Y por detalle
// Captura movimientos donde el banco se menciona en el detalle aunque la
// cuenta contable sea distinta (ej: transferencias intermedias).
// LEFT JOIN en valores para no perder items con DEBE o HABER faltante.

var periodo = (msg._periodo || '2026-02').replace('-', '');
var cuenta = msg._cuenta || '01.01.01.02.04';
var banco = msg._banco || 'Galicia';

// Extraer prefijo de cuenta para LIKE (ej: "01.01.01.02.04" → "01.01.01.02.04%")
var cuentaPrefix = cuenta.split(' - ')[0] + '%';

var query = 'SELECT DISTINCT ' +
  ' SUBSTRING(t.FECHAAPLICACION,1,8) AS FECHA,' +
  ' t.NUMERODOCUMENTO AS ASIENTO,' +
  ' t.DETALLE,' +
  ' COALESCE(v1.IMPORTE, 0) AS DEBE,' +
  ' COALESCE(v2.IMPORTE, 0) AS HABER,' +
  ' t.NOMBREDESTINATARIO AS PROVEEDOR' +
' FROM V_TRCONTABLE_ t' +
' INNER JOIN V_ITEMCONTABLE_ ic ON t.ITEMSTRANSACCION_ID = ic.BO_PLACE_ID' +
' LEFT JOIN V_VALOR_ v1 ON ic.DEBE_ID = v1.ID' +
' LEFT JOIN V_VALOR_ v2 ON ic.HABER_ID = v2.ID' +
' INNER JOIN V_EZI_CUENTAS ec ON ic.REFERENCIA_ID = ec.ID' +
" WHERE (ec.CODIGO LIKE '" + cuentaPrefix + "'" +
  " OR t.DETALLE LIKE '%" + banco + "%'" +
  " OR t.DETALLE LIKE '%Banco%')" +
  " AND SUBSTRING(t.FECHAAPLICACION,1,6) = '" + periodo + "'" +
  " AND t.ESTADO = 'C'" +
' ORDER BY t.FECHAAPLICACION ASC';

msg.payload = query;
msg._periodo = periodo;
msg._cuenta = cuenta;
msg._banco = banco;
node.warn('[Conciliacion] Consultando Calipso ' + banco + ' periodo ' + periodo + ' (query mejorado)...');
return msg;

var rows = msg.payload;
var periodo = msg._periodo || '2026-02';  // ← editar en inject
var cuenta = msg._cuenta || '01.01.01.02.04';

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Conciliacion] Calipso sin datos');
  msg._empty = true;
  return msg;
}

// 1. Marcar reversiones
var reversiones = {};
for (var i = 0; i < rows.length; i++) {
  var det = (rows[i].DETALLE || '').toString();
  var match = det.match(/Reversi[oó]n Nro\.?\s*(\d+)/i);
  if (match) {
    var nroRev = match[1];
    if (!reversiones[nroRev]) reversiones[nroRev] = [];
    reversiones[nroRev].push(i);
    rows[i]._esReversion = true;
  } else {
    rows[i]._esReversion = false;
  }
}

// Contar pares de reversión
var paresEliminados = 0;
var keys = Object.keys(reversiones);
for (var k = 0; k < keys.length; k++) {
  if (reversiones[keys[k]].length >= 2) paresEliminados++;
}

// 2. Construir array 2D (sin filas de reversión)
var data = [];
for (var j = 0; j < rows.length; j++) {
  var r = rows[j];
  // Saltar filas que son parte de un par de reversión
  var revKey = null;
  var det2 = (r.DETALLE || '').toString();
  var match2 = det2.match(/Reversi[oó]n Nro\.?\s*(\d+)/i);
  if (match2 && reversiones[match2[1]] && reversiones[match2[1]].length >= 2) continue;

  var debe = parseFloat(r.DEBE) || 0;
  var haber = parseFloat(r.HABER) || 0;
  var neto = debe - haber;

  data.push([
    r.FECHA || '',
    r.ASIENTO || '',
    (r.DETALLE || '').substring(0, 250),
    debe,
    haber,
    neto,
    r._esReversion ? 'SI' : 'NO',
    cuenta
  ]);
}

msg._newRows = data;
msg._paresEliminados = paresEliminados;
msg._totalRows = rows.length;
msg._depurados = data.length;

node.warn('[Conciliacion] Calipso: ' + rows.length + ' filas, ' + paresEliminados + ' pares revertidos, ' + data.length + ' depuradas');
return msg;

var newRows = msg._newRows || [];
var existing = msg.payload || [];

if (msg._empty || newRows.length === 0) {
  msg.payload = null;
  return msg;
}

// Clave: FECHA|ASIENTO (col 0 + 1)
var existingKeys = new Set();
if (Array.isArray(existing)) {
  for (var i = 0; i < existing.length; i++) {
    var row = existing[i];
    if (Array.isArray(row) && row.length >= 2) {
      existingKeys.add(String(row[0] || '').trim() + '|' + String(row[1] || '').trim());
    }
  }
}

var filtered = [];
for (var j = 0; j < newRows.length; j++) {
  var key = String(newRows[j][0] || '').trim() + '|' + String(newRows[j][1] || '').trim();
  if (!existingKeys.has(key)) filtered.push(newRows[j]);
}

msg._calipsoNew = filtered.length;
msg._calipsoSkip = newRows.length - filtered.length;

if (filtered.length === 0) {
  msg.payload = null;
} else {
  msg.payload = filtered;
}

node.warn('[Conciliacion] Calipso dedup: ' + newRows.length + ' nuevas, ' + (newRows.length - filtered.length) + ' ya existen, ' + filtered.length + ' a escribir');
return msg;

var range = (msg.payload && msg.payload.updates) ? msg.payload.updates.updatedRange : '';
node.warn('[Conciliacion] Calipso OK: ' + (msg._calipsoNew || 0) + ' filas nuevas → ' + range);
return msg;

// Periodo desde inject (editarlo allí) o default
msg._periodo = msg._periodo || '2026-02';
msg._banco = msg._banco || 'Galicia';
node.warn('[Conciliacion] Iniciando cruce ' + msg._banco + ' ' + msg._periodo + '...');
return msg;

// ============================================================
// NODO: Conciliacion - Cruce Banco vs Calipso V2
// MEJORAS:
//   1. Matching multi-criterio en 4 niveles de precision
//   2. Deteccion de pares MEP (compra + venta)
//   3. Trazabilidad: calidad de match en resultados
//   4. Periodo derivado dinamicamente de datos bancarios
// ============================================================

var banco = flow.get('conc_banco_rows') || [];
var calipso = msg.payload || [];

node.warn('[Conciliacion] CRUCE V2: ' + banco.length + ' banco vs ' + calipso.length + ' calipso');

// === UTILIDADES ===
function fechaDiff(f1, f2) {
  if (!f1 || !f2 || f1.length < 8 || f2.length < 8) return 999;
  var a = new Date(f1.slice(0, 4) + '-' + f1.slice(4, 6) + '-' + f1.slice(6, 8));
  var b = new Date(f2.slice(0, 4) + '-' + f2.slice(4, 6) + '-' + f2.slice(6, 8));
  if (isNaN(a) || isNaN(b)) return 999;
  return Math.abs((a - b) / 86400000);
}

function mismSigno(a, b) {
  return (a >= 0 && b >= 0) || (a < 0 && b < 0);
}

// === CLASIFICACION DEL EXTRACTO BANCARIO ===
var TIPO_MAP = {
  '000912': 'Cheques/ECheqs', '000914': 'Gestion Cheque',
  '000909': 'Servicio Pago Proveedores', '000916': 'FIMA',
  '000083': 'Debito Automatico', '000908': 'Haberes',
  '000910': 'Prestamo', '000901': 'Gasto/Impuesto',
  '000808': 'Gasto/Impuesto', '000814': 'Gasto/Impuesto',
  '000833': 'Acreditacion Canje', '000903': 'Rechazo Debito',
  '000915': 'Deposito Efectivo', '000917': 'COMEX',
  '000907': 'Transferencia'
};

var SUBTIPO_907 = {
  '907255': 'Pago AFIP', '917203': 'MEP',
  '917193': 'Cobro Cash Prov (YPF)', '917180': 'COMEX',
  '907269': 'Pago Proveedor', '907232': 'Pago Proveedor',
  '907297': 'Transf Propia CP', '907268': 'Transf Propia CP',
  '917152': 'Transf Cta Propia', '917151': 'Transf Terceros'
};

// Clasificar movimientos del banco (formato enriquecido)
var bancoClasif = [];
for (var i = 0; i < banco.length; i++) {
  var b = banco[i];

  var grupo = String(b.grupo || '').trim();
  var concepto = String(b.concepto || '').trim();
  var desc = String(b.descripcion || '').trim();

  var tipo = TIPO_MAP[grupo] || 'Otros';

  if (grupo === '000907' && SUBTIPO_907[concepto]) tipo = SUBTIPO_907[concepto];

  if (grupo === '000916') {
    tipo = desc.toLowerCase().indexOf('suscripcion') >= 0 ? 'FIMA Suscripcion' : 'FIMA Rescate';
  }

  var esGasto = (['000901', '000808', '000814'].indexOf(grupo) >= 0) ||
    (grupo === '000907' && ['907171', '907173'].indexOf(concepto) >= 0);

  var importeNeto = b.importeNeto || 0;

  bancoClasif.push({
    fecha: String(b.fecha || '').trim(),
    descripcion: desc,
    tipo: tipo,
    grupo: grupo,
    concepto: concepto,
    importe: importeNeto,
    debito: b.debito || 0,
    credito: b.credito || 0,
    esGasto: esGasto,
    saldo: b.saldo || 0,
    nroComprobante: String(b.nroComprobante || '').trim()
  });
}

// === MATCHING MULTI-CRITERIO (4 NIVELES) ===
var resultados = [];
var pendientes = [];
var calipsoUsados = {};
var totalBanco = 0;
var totalCalipso = 0;

// Nivel 1: Match por Nro Comprobante (banco) vs ASIENTO (Calipso)
// Nivel 2: Importe EXACTO + misma fecha
// Nivel 3: Importe +/- 1% + fecha +/- 1 dia
// Nivel 4: Importe +/- 1% + fecha +/- 3 dias

function matchScore(bancoItem, calipsoRow, nivel) {
  var calFecha = String(calipsoRow[0] || '').trim();
  var calAsiento = String(calipsoRow[1] || '').trim();
  var calNeto = parseFloat(calipsoRow[5]) || 0;

  // Mismo signo: deben ser ambos positivos o ambos negativos
  // (banco: positivo=ingreso/credito, negativo=egreso/debito)
  if (!mismSigno(bancoItem.importe, calNeto)) return false;

  var diffDias = fechaDiff(bancoItem.fecha, calFecha);

  switch (nivel) {
    case 1: // Nro Comprobante
      return bancoItem.nroComprobante &&
             bancoItem.nroComprobante.length > 0 &&
             bancoItem.nroComprobante === calAsiento;

    case 2: // Importe EXACTO + misma fecha
      return Math.abs(bancoItem.importe - calNeto) < 0.01 && diffDias === 0;

    case 3: // Importe +/- 1% + fecha +/- 1 dia
      var diffImp = Math.abs(bancoItem.importe - calNeto);
      var tolerancia = Math.abs(bancoItem.importe) * 0.01;
      return diffImp < tolerancia && diffDias <= 1;

    case 4: // Importe +/- 1% + fecha +/- 3 dias (fallback)
      var diffImp4 = Math.abs(bancoItem.importe - calNeto);
      var tolerancia4 = Math.abs(bancoItem.importe) > 5000
        ? Math.abs(bancoItem.importe) * 0.01
        : 10;
      return diffImp4 < tolerancia4 && diffDias <= 3;

    default:
      return false;
  }
}

// Procesar cada movimiento bancario contra Calipso
for (var bi = 0; bi < bancoClasif.length; bi++) {
  var bm = bancoClasif[bi];
  var mejorMatch = null;
  var mejorNivel = 0;
  var mejorIdx = -1;
  var mejorDif = Infinity;
  var calAsientoMatch = '';

  // Buscar en los 4 niveles (de mas preciso a menos)
  for (var nivel = 1; nivel <= 4; nivel++) {
    if (mejorMatch) break; // Ya encontro match en nivel anterior

    for (var ci = 0; ci < calipso.length; ci++) {
      if (calipsoUsados[ci]) continue;
      var cm = calipso[ci];
      if (!Array.isArray(cm) || cm.length < 6) continue;

      if (matchScore(bm, cm, nivel)) {
        var calNeto = parseFloat(cm[5]) || 0;
        var dif = Math.abs(bm.importe - calNeto);
        if (dif < mejorDif) {
          mejorDif = dif;
          mejorMatch = cm;
          mejorIdx = ci;
          mejorNivel = nivel;
          calAsientoMatch = String(cm[1] || '').trim();
        }
      }
    }
  }

  if (mejorMatch && mejorIdx >= 0) {
    calipsoUsados[mejorIdx] = true;
    var calImporte = parseFloat(mejorMatch[5]) || 0;
    var dif2 = Math.abs(bm.importe - calImporte);
    var nivelLabel = 'N' + mejorNivel;
    var estadoMatch = (mejorNivel <= 2) ? 'CONCILIADO' : 'TIMING';

    resultados.push({
      fecha: bm.fecha,
      tipo: bm.tipo,
      descripcion: bm.descripcion,
      banco: bm.importe,
      calipso: calImporte,
      dif: dif2,
      estado: estadoMatch,
      criticidad: 'OK',
      calidad: nivelLabel,
      asiento: calAsientoMatch
    });
    totalBanco += bm.importe;
    totalCalipso += calImporte;

  } else {
    // NO encontrado en Calipso → PENDIENTE / SOLO_BANCO
    var crit = 'MEDIA';
    if (Math.abs(bm.importe) > 10000000) crit = 'CRITICA';
    else if (Math.abs(bm.importe) > 1000000) crit = 'ALTA';
    else if (bm.esGasto) crit = 'ALTA';

    resultados.push({
      fecha: bm.fecha,
      tipo: bm.tipo,
      descripcion: bm.descripcion,
      banco: bm.importe,
      calipso: 0,
      dif: Math.abs(bm.importe),
      estado: 'SOLO_BANCO',
      criticidad: crit,
      calidad: 'SIN_MATCH',
      asiento: ''
    });
    pendientes.push({
      banco: 'Galicia',
      fecha: bm.fecha,
      descripcion: bm.descripcion,
      importe: Math.abs(bm.importe),
      tipo: bm.tipo,
      origen: 'BANCO',
      criticidad: crit,
      nroComprobante: bm.nroComprobante,
      observacion: bm.esGasto
        ? 'GASTO BANCARIO - Verificar registro en Calipso'
        : 'No encontrado en Calipso (ningun nivel de match)'
    });
    totalBanco += bm.importe;
  }
}

// Items en Calipso NO conciliados (SOLO_CALIPSO)
for (var ci2 = 0; ci2 < calipso.length; ci2++) {
  if (calipsoUsados[ci2]) continue;
  var cm2 = calipso[ci2];
  if (!Array.isArray(cm2) || cm2.length < 6) continue;

  var calNeto2 = parseFloat(cm2[5]) || 0;
  if (isNaN(calNeto2)) calNeto2 = 0;
  if (Math.abs(calNeto2) < 0.01) continue;

  var crit2 = 'MEDIA';
  if (Math.abs(calNeto2) > 10000000) crit2 = 'CRITICA';
  else if (Math.abs(calNeto2) > 1000000) crit2 = 'ALTA';

  resultados.push({
    fecha: String(cm2[0] || '').trim(),
    tipo: 'Mov Calipso',
    descripcion: String(cm2[2] || '').trim().substring(0, 100),
    banco: 0,
    calipso: calNeto2,
    dif: Math.abs(calNeto2),
    estado: 'SOLO_CALIPSO',
    criticidad: crit2,
    calidad: '',
    asiento: String(cm2[1] || '').trim()
  });
  pendientes.push({
    banco: 'Galicia',
    fecha: String(cm2[0] || '').trim(),
    descripcion: String(cm2[2] || '').trim().substring(0, 150),
    importe: Math.abs(calNeto2),
    tipo: 'Mov Calipso',
    origen: 'CALIPSO',
    criticidad: crit2,
    nroComprobante: '',
    observacion: 'Registrado en Calipso pero no en extracto bancario - Posible TIMING'
  });
  totalCalipso += calNeto2;
}

// === DETECCION DE PARES MEP ===
// Buscar pares compra+venta MEP del mismo importe aproximado
var paresMEP = [];
for (var pi = 0; pi < pendientes.length; pi++) {
  var p1 = pendientes[pi];
  if (p1.tipo !== 'MEP') continue;
  if (p1.criticidad === 'OK') continue; // ya emparejado

  for (var pj = pi + 1; pj < pendientes.length; pj++) {
    var p2 = pendientes[pj];
    if (p2.tipo !== 'MEP') continue;
    if (p2.criticidad === 'OK') continue;

    var difMEP = Math.abs(p1.importe - p2.importe);
    var maxImp = Math.max(p1.importe, p2.importe);
    if (maxImp > 0 && (difMEP / maxImp) < 0.02) {
      // Es un par MEP
      p1.criticidad = 'OK';
      p1.observacion = 'Par MEP identificado - Timing normal (clearing)';
      p2.criticidad = 'OK';
      p2.observacion = 'Par MEP identificado - Timing normal (clearing)';
      paresMEP.push({ a: 'Venta MEP', b: 'Compra MEP', importe: p1.importe });
    }
  }
}

if (paresMEP.length > 0) {
  node.warn('[Conciliacion] PARES MEP detectados: ' + paresMEP.length);
}

var totalDiferencia = totalBanco - totalCalipso;

// Ordenar pendientes por criticidad (CRITICA primero)
var critOrder = { 'CRITICA': 0, 'ALTA': 1, 'MEDIA': 2, 'OK': 3 };
pendientes.sort(function (a, b) {
  return (critOrder[a.criticidad] || 3) - (critOrder[b.criticidad] || 3);
});

// === PREPARAR RESULTADOS PARA SHEETS ===
// Conciliacion: FECHA|TIPO|DESCRIPCION|BANCO|CALIPSO|DIF|ESTADO|CRITICIDAD|CALIDAD|ASIENTO
var conciliacion2D = [];
for (var ri = 0; ri < resultados.length; ri++) {
  var r = resultados[ri];
  conciliacion2D.push([
    r.fecha, r.tipo, r.descripcion.substring(0, 200),
    r.banco, r.calipso, r.dif, r.estado, r.criticidad,
    r.calidad || '', r.asiento || ''
  ]);
}

// Pendientes: BANCO|FECHA|DESCRIPCION|IMPORTE|TIPO|ORIGEN|CRITICIDAD|OBSERVACION|NROCOMP
var pendientes2D = [];
for (var pi2 = 0; pi2 < pendientes.length; pi2++) {
  var p = pendientes[pi2];
  pendientes2D.push([
    p.banco, p.fecha, p.descripcion.substring(0, 200),
    p.importe, p.tipo, p.origen, p.criticidad, p.observacion,
    p.nroComprobante || ''
  ]);
}

// Resumen: BANCO|PERIODO|TOTAL_BANCO|TOTAL_CALIPSO|DIFERENCIA|N_CONCILIADOS|SEMAFORO|PENDIENTES
var periodo = bancoClasif.length
  ? bancoClasif[0].fecha.replace(/^(\d{4})(\d{2})\d{2}$/, '$1-$2')
  : '????-??';

// Contar solo pendientes REALES (criticidad != OK y origen != CALIPSO)
var pendientesReales = pendientes.filter(function(p) {
  return p.criticidad !== 'OK';
}).length;

var estadoResumen = Math.abs(totalDiferencia) < 100
  ? 'CUADRADO'
  : (Math.abs(totalDiferencia) < 500000 ? 'TIMING' : 'PENDIENTE');
var semaforo = estadoResumen === 'CUADRADO'
  ? 'VERDE'
  : (estadoResumen === 'TIMING' ? 'AMARILLO' : 'ROJO');

var resumen2D = [[
  'Galicia',
  periodo,
  totalBanco,
  totalCalipso,
  totalDiferencia,
  resultados.filter(function(x) { return x.estado === 'CONCILIADO'; }).length,
  semaforo,
  pendientesReales
]];

// Guardar en context
flow.set('conc_resultados', conciliacion2D);
flow.set('conc_pendientes', pendientes2D);
flow.set('conc_resumen', resumen2D);

var stats = {
  totalResultados: resultados.length,
  conciliados: resultados.filter(function(x) { return x.estado === 'CONCILIADO'; }).length,
  soloBanco: resultados.filter(function(x) { return x.estado === 'SOLO_BANCO'; }).length,
  soloCalipso: resultados.filter(function(x) { return x.estado === 'SOLO_CALIPSO'; }).length,
  timing: resultados.filter(function(x) { return x.estado === 'TIMING'; }).length,
  pendientes: pendientesReales,
  criticas: pendientes.filter(function(x) { return x.criticidad === 'CRITICA'; }).length,
  altas: pendientes.filter(function(x) { return x.criticidad === 'ALTA'; }).length,
  diferencia: totalDiferencia,
  semaforo: semaforo,
  paresMEP: paresMEP.length,
  calNiveles: {
    n1: resultados.filter(function(x) { return x.calidad === 'N1'; }).length,
    n2: resultados.filter(function(x) { return x.calidad === 'N2'; }).length,
    n3: resultados.filter(function(x) { return x.calidad === 'N3'; }).length,
    n4: resultados.filter(function(x) { return x.calidad === 'N4'; }).length,
    sinMatch: resultados.filter(function(x) { return x.calidad === 'SIN_MATCH'; }).length
  }
};

flow.set('conc_stats', stats);

node.warn('[Conciliacion] CRUCE V2 COMPLETO:');
node.warn('[Conciliacion]   Niveles: N1=' + stats.calNiveles.n1 +
  ' N2=' + stats.calNiveles.n2 +
  ' N3=' + stats.calNiveles.n3 +
  ' N4=' + stats.calNiveles.n4 +
  ' SIN=' + stats.calNiveles.sinMatch);
node.warn('[Conciliacion]   Pendientes: ' + pendientesReales +
  ' (' + stats.criticas + ' CRIT, ' + stats.altas + ' ALT)');
node.warn('[Conciliacion]   MEP pairs: ' + paresMEP.length);
node.warn('[Conciliacion]   Semaforo: ' + semaforo + ' | Dif: $' +
  (typeof totalDiferencia === 'number' && !isNaN(totalDiferencia)
    ? totalDiferencia.toFixed(2) : '???'));

msg._conciliacionLista = true;
return [msg, null, null];

// FIX 1: Eliminada "var flow = flow" — innecesaria y confusa.
// FIX 2: Validacion con Array.isArray en lugar de solo truthy check.

var data = flow.get('conc_resultados');

if (Array.isArray(data) && data.length > 0) {
  msg.payload    = data;
  msg._sheetType = 'conciliacion';
  return msg;
}

node.warn('[Conciliacion] conc_resultados vacio o no es array — nodo no dispara.');
return null;

var flow = flow;
var data = flow.get('conc_pendientes');
if (data && data.length > 0) {
  msg.payload = data;
  msg._sheetType = 'pendientes';
  return msg;
}
return null;

var flow = flow;
var data = flow.get('conc_resumen');
if (data && data.length > 0) {
  msg.payload = data;
  msg._sheetType = 'resumen';
  return msg;
}
return null;

// FIX 1: Eliminada "var flow = flow" — innecesaria y confusa.
// FIX 2: Validacion con typeof para asegurar que stats es un objeto real.
// FIX 3: toFixed(2) protegido contra diferencia undefined/null/NaN.
// FIX 4: Warn si stats no existe, para no perder trazabilidad.

var stats = flow.get('conc_stats');

if (stats && typeof stats === 'object') {
  var dif = typeof stats.diferencia === 'number' && !isNaN(stats.diferencia)
    ? stats.diferencia.toFixed(2)
    : '???';

  node.warn('[Conciliacion] ═══════════════════════');
  node.warn('[Conciliacion] RESUMEN FINAL:');
  node.warn('[Conciliacion]   Conciliados:  ' + (stats.conciliados  || 0));
  node.warn('[Conciliacion]   Solo Banco:   ' + (stats.soloBanco    || 0));
  node.warn('[Conciliacion]   Solo Calipso: ' + (stats.soloCalipso  || 0));
  node.warn('[Conciliacion]   Timing:       ' + (stats.timing       || 0));
  node.warn('[Conciliacion]   PENDIENTES:   ' + (stats.pendientes   || 0) +
    ' (' + (stats.criticas || 0) + ' CRITICAS, ' + (stats.altas || 0) + ' ALTAS)');
  node.warn('[Conciliacion]   Semaforo:     ' + (stats.semaforo     || 'N/A'));
  node.warn('[Conciliacion]   Diferencia:   $' + dif);
  node.warn('[Conciliacion] ═══════════════════════');
} else {
  node.warn('[Conciliacion] conc_stats no disponible — el nodo de cruce aun no ejecuto.');
}

return msg;

// Guardar filas del banco con nro comprobante
var filas = Array.isArray(msg.payload) ? msg.payload : [];

// Enriquecer con nroComprobante (columna H, índice 7)
var enriquecidas = [];
for (var i = 0; i < filas.length; i++) {
  var f = filas[i];
  enriquecidas.push({
    fecha: String(f[0] || '').trim(),
    descripcion: String(f[1] || '').trim(),
    debito: parseFloat(f[2]) || 0,
    credito: parseFloat(f[3]) || 0,
    grupo: String(f[4] || '').trim(),
    concepto: String(f[5] || '').trim(),
    nroComprobante: String(f[7] || '').trim(),   // Columna H
    saldo: parseFloat(f[8]) || 0,
    importeNeto: (parseFloat(f[3]) || 0) - (parseFloat(f[2]) || 0)
  });
}

flow.set('conc_banco_rows', enriquecidas);

node.warn('[Conciliacion] Banco: ' + enriquecidas.length + ' filas guardadas (enriquecidas). Disparando lectura Calipso...');
return msg;

// Si _periodo viene vacio (desde el scheduler), derivar mes actual
if (!msg._periodo || msg._periodo === '') {
  var ahora = new Date();
  var mes = ahora.getMonth() + 1;
  var anio = ahora.getFullYear();
  // Si estamos en los primeros 5 dias del mes, conciliar el mes anterior
  if (ahora.getDate() <= 5) {
    mes -= 1;
    if (mes === 0) { mes = 12; anio -= 1; }
  }
  msg._periodo = anio + '-' + (mes < 10 ? '0' : '') + mes;
  msg._periodoNum = msg._periodo.replace('-', '');
  node.warn('[Conciliacion] Periodo auto-derivado: ' + msg._periodo);
}
return msg;

// Crear entrada de historial con stats de la ejecucion
var stats = flow.get('conc_stats');

if (stats && typeof stats === 'object') {
  var ahora = new Date();
  var fechaHora = ahora.getFullYear() + '-' +
    ('0' + (ahora.getMonth()+1)).slice(-2) + '-' +
    ('0' + ahora.getDate()).slice(-2) + ' ' +
    ('0' + ahora.getHours()).slice(-2) + ':' +
    ('0' + ahora.getMinutes()).slice(-2) + ':' +
    ('0' + ahora.getSeconds()).slice(-2);

  var logEntry = [
    fechaHora,
    'Galicia',
    flow.get('conc_resumen') && flow.get('conc_resumen')[0]
      ? flow.get('conc_resumen')[0][1] : '????-??',
    stats.conciliados || 0,
    stats.soloBanco || 0,
    stats.soloCalipso || 0,
    stats.timing || 0,
    stats.pendientes || 0,
    stats.criticas || 0,
    stats.altas || 0,
    typeof stats.diferencia === 'number' ? stats.diferencia : 0,
    stats.semaforo || 'N/A',
    stats.paresMEP || 0
  ];

  msg.payload = [logEntry];
  msg._sheetType = 'historial';
  node.warn('[Conciliacion] Log: ' + fechaHora + ' | ' + stats.semaforo +
    ' | Dif: $' + stats.diferencia);
} else {
  node.warn('[Conciliacion] Log: stats no disponible');
  return null;
}

return msg;
